class Solution:
    def maximumNumber(self, num, change):
        n = len(num)
        best = num
        for i in range(n):
            cand = list(num)
            j = i
            while j < n:
                d = int(num[j])
                m = change[d]
                if m < d:
                    break
                cand[j] = str(m)
                j += 1
            cur = ''.join(cand)
            if cur > best:
                best = cur
        return best

