class Solution:
    def maximumNumber(self, num, change):
        digits = list(num)
        started = False
        for i, ch in enumerate(digits):
            d = int(ch)
            mapped = change[d]
            if mapped > d:
                digits[i] = str(mapped)
                started = True
            elif mapped == d and started:
                continue
            elif mapped < d and started:
                break
            elif started:
                break
        return ''.join(digits)

