var maximumNumber = function(num, change) {
    const digits = num.split('');
    let started = false;
    for (let i = 0; i < digits.length; i++) {
        const d = digits[i].charCodeAt(0) - 48;
        const mapped = change[d];
        if (mapped > d) {
            digits[i] = String(mapped);
            started = true;
        } else if (mapped === d && started) {
            continue;
        } else if (started) {
            break;
        }
    }
    return digits.join('');
};
